function setupTemplateFileUpload() {
  const uploadBtn = document.getElementById("upload-template-files");
  const fileInput = document.getElementById("template-file-input");
  const templateEditor = getDemoEditor("template-input-text");
  const tabsScroll = document.getElementById("template-file-tabs-scroll");
  if (!uploadBtn || !fileInput || !templateEditor)
    return;
  uploadBtn.addEventListener("click", () => fileInput.click());
  tabsScroll?.addEventListener("change", (e2) => {
    const target = e2.target;
    if (target.name === "template-generation-root" && target.type === "radio" && target.checked) {
      clinicalWorkspace.setGenerationRootPath(target.value);
      updateTemplateFileSetUi();
      handleInputChange("template");
    }
  });
  tabsScroll?.addEventListener("click", (e2) => {
    const btn = e2.target.closest(
      ".template-file-tab-btn"
    );
    if (!btn?.dataset.path)
      return;
    selectTemplateFileTab(btn.dataset.path);
  });
  templateEditor.onChange(() => {
    const path = clinicalWorkspace.getActivePath();
    if (path) {
      clinicalWorkspace.updateFileContent(path, templateEditor.value);
      updateTemplateFileSetUi();
    }
  });
  fileInput.addEventListener("change", async () => {
    const files = fileInput.files;
    if (!files?.length)
      return;
    let lastPath;
    for (const file of Array.from(files)) {
      const name2 = file.name.toLowerCase();
      if (name2.endsWith(".zip")) {
        const buf = new Uint8Array(await file.arrayBuffer());
        const entries = unzipSync(buf);
        const batch = [];
        for (const [entryName, data] of Object.entries(entries)) {
          batch.push({
            path: entryName.replace(/\\/g, "/").replace(/^\/+/, ""),
            content: strFromU8(data)
          });
        }
        if (batch.length) {
          const results = clinicalWorkspace.loadFromZipEntries(batch);
          if (results.length) {
            lastPath = results[results.length - 1]?.path;
          }
        }
        continue;
      }
      if (/\.(opt|oet|adl|adls|t\.json|xml)$/i.test(name2)) {
        const result2 = clinicalWorkspace.addFile(file.name, await file.text());
        lastPath = result2.path;
      }
    }
    if (clinicalWorkspace.listFiles().length) {
      const root = ClinicalModelWorkspace.suggestGenerationRoot(
        clinicalWorkspace.listFiles()
      );
      if (root)
        clinicalWorkspace.setGenerationRootPath(root);
      selectTemplateFileTab(
        lastPath ?? root ?? clinicalWorkspace.getActivePath() ?? ""
      );
      activateInputTab("template");
      handleInputChange("template");
    }
    fileInput.value = "";
  });
}
function setupTemplateAdGitLoad() {
  const loadBtn = document.getElementById("load-github-template");
  const urlInput = document.getElementById("github-template-url");
  if (!loadBtn || !urlInput)
    return;
  const defaultUrl = "https://github.com/regionstockholm/CKM-mirror-via-modellbibliotek/blob/MultiDiciplinery_Tumor_meetings/local/Diagnostic_MDT_Lung_cancer.t.json";
  if (!urlInput.value.trim())
    urlInput.value = defaultUrl;
  loadBtn.addEventListener("click", async () => {
    const url = urlInput.value.trim();
    if (!url) {
      alert("Paste a GitHub blob or raw URL to a .t.json template file.");
      return;
    }
    loadBtn.setAttribute("disabled", "true");
    clearAdGitProgress();
    appendAdGitProgress("Starting\u2026", "parse-url");
    try {
      const result2 = await clinicalWorkspace.loadFromGitHubTemplateUrl(url, {
        onProgress: (e2) => {
          appendAdGitProgress(e2.message, e2.phase, e2.path);
        },
        maxFiles: 200
      });
      for (const w2 of result2.warnings) {
        appendAdGitProgress(w2, "resolve");
      }
      appendAdGitProgress(
        `Done \u2014 ${result2.fetched} files loaded (root: ${result2.rootPath})`,
        "complete"
      );
      if (result2.rootPath)
        selectTemplateFileTab(result2.rootPath);
      updateTemplateFileSetUi();
      activateInputTab("template");
      handleInputChange("template");
      void handleConvert();
    } catch (e2) {
      appendAdGitProgress(e2.message, "fetch");
      alert(`Template load failed: ${e2.message}`);
    } finally {
      loadBtn.removeAttribute("disabled");
    }
  });
}
function clearAdGitProgress() {
  const empty = document.getElementById("adgit-progress-empty");
  const list = document.getElementById("adgit-progress-list");
  if (empty)
    empty.classList.remove("hidden");
  if (list) {
    list.innerHTML = "";
    list.classList.add("hidden");
  }
}
function appendAdGitProgress(message, phase, _path) {
  const empty = document.getElementById("adgit-progress-empty");
  const list = document.getElementById("adgit-progress-list");
  if (!list)
    return;
  if (empty)
    empty.classList.add("hidden");
  list.classList.remove("hidden");
  const li2 = document.createElement("li");
  if (phase === "complete")
    li2.classList.add("adgit-phase-complete");
  if (phase === "fetch" && message.startsWith("Failed")) {
    li2.classList.add("adgit-phase-error");
  }
  li2.textContent = message;
  list.appendChild(li2);
  list.scrollTop = list.scrollHeight;
}
